/**
 * @param {number} n
 * @param {number} m
 * @param {number[][]} sources
 * @return {number[][]}
 */
function solve(n, m, sources) {
    // This problem can be solved using a multi-source Breadth-First Search (BFS)
    // where the "distance" is the time it takes for the color to reach a cell,
    // and we prioritize higher colors in case of a tie in time.

    // Initialize the grid: 0 means uncolored, -1 means unvisited/uninitialized for distance tracking
    // We will store the time it took to reach this cell and the color that reached it.
    // Let's use a distance array/grid for BFS and a separate color grid.

    // dist[r][c] stores the minimum time step for any color to reach (r, c).
    const dist = Array(n).fill(0).map(() => Array(m).fill(Infinity));
    // finalColor[r][c] stores the final color of cell (r, c).
    const finalColor = Array(n).fill(0).map(() => Array(m).fill(0));

    // Priority Queue for the BFS.
    // The queue stores elements: [time, -color, r, c]
    // We use negative color because we want a Max-Heap behavior on color (higher color first)
    // when times are equal, but standard priority queues often implement Min-Heap.
    // Since we are simulating the simultaneous spread, the standard BFS layer-by-layer approach is better.
    // However, because of the "max color wins" rule, a Dijkstra-like approach prioritizing
    // (time, -color) is most suitable.

    // For Dijkstra/Priority Queue: prioritize smaller time, then larger color.
    // Element format: [time, -color, r, c]
    const pq = [];

    // Initialize PQ with all sources
    for (const [r, c, color] of sources) {
        dist[r][c] = 0;
        finalColor[r][c] = color;
        // Push [time, color_negated, r, c]
        pq.push([0, -color, r, c]);
    }

    // Simple custom priority queue implementation (min-heap based on time, then color_negated)
    // In JavaScript, simulating a heap is often easier with an array and sorting/sifting,
    // but given constraints (N*M <= 10^5), a simple sorted array might suffice if the number of updates isn't huge,
    // but a proper Min-Heap is safer. Let's implement a basic MinHeap structure for correctness.

    class MinPriorityQueue {
        constructor() {
            this.heap = [];
        }

        isEmpty() {
            return this.heap.length === 0;
        }

        _getParentIndex(i) { return Math.floor((i - 1) / 2); }
        _getLeftChildIndex(i) { return 2 * i + 1; }
        _getRightChildIndex(i) { return 2 * i + 2; }

        _swap(i, j) {
            [this.heap[i], this.heap[j]] = [this.heap[j], this.heap[i]];
        }

        _compare(a, b) {
            // Comparison: 
            // 1. Smaller time comes first (a[0] < b[0])
            // 2. If times are equal, larger color comes first (smaller -color, so a[1] < b[1])
            if (a[0] !== b[0]) {
                return a[0] - b[0]; // Min time
            }
            return a[1] - b[1]; // Min negative color (Max color)
        }

        enqueue(element) {
            this.heap.push(element);
            this._bubbleUp(this.heap.length - 1);
        }

        dequeue() {
            if (this.isEmpty()) return null;
            if (this.heap.length === 1) return this.heap.pop();

            const min = this.heap[0];
            this.heap[0] = this.heap.pop();
            this._bubbleDown(0);
            return min;
        }

        _bubbleUp(index) {
            let currentIndex = index;
            let parentIndex = this._getParentIndex(currentIndex);
            while (currentIndex > 0 && this._compare(this.heap[currentIndex], this.heap[parentIndex]) < 0) {
                this._swap(currentIndex, parentIndex);
                currentIndex = parentIndex;
                parentIndex = this._getParentIndex(currentIndex);
            }
        }

        _bubbleDown(index) {
            let currentIndex = index;
            const lastIndex = this.heap.length - 1;

            while (true) {
                let left = this._getLeftChildIndex(currentIndex);
                let right = this._getRightChildIndex(currentIndex);
                let smallest = currentIndex;

                // Check left child
                if (left <= lastIndex && this._compare(this.heap[left], this.heap[smallest]) < 0) {
                    smallest = left;
                }

                // Check right child
                if (right <= lastIndex && this._compare(this.heap[right], this.heap[smallest]) < 0) {
                    smallest = right;
                }

                if (smallest !== currentIndex) {
                    this._swap(currentIndex, smallest);
                    currentIndex = smallest;
                } else {
                    break;
                }
            }
        }
    }

    const pqInstance = new MinPriorityQueue();
    for (const [r, c, color] of sources) {
        // Time 0, Negative Color, R, C
        pqInstance.enqueue([0, -color, r, c]);
    }


    const directions = [[0, 1], [0, -1], [1, 0], [-1, 0]];

    while (!pqInstance.isEmpty()) {
        const [time, negColor, r, c] = pqInstance.dequeue();
        const currentColor = -negColor;

        // Check for stale entries (if we found a faster/better path already)
        // If the recorded time/color is strictly better than what we pulled, skip.
        // Note: In Dijkstra, we only skip if the pulled distance is worse than the recorded one.
        // Here, "worse" means (time > recorded_time) OR (time == recorded_time AND color < recorded_color).
        if (time > dist[r][c] || (time === dist[r][c] && currentColor < finalColor[r][c])) {
            continue;
        }


        // Spread to neighbors
        for (const [dr, dc] of directions) {
            const nr = r + dr;
            const nc = c + dc;

            if (nr >= 0 && nr < n && nc >= 0 && nc < m) {
                const newTime = time + 1;

                // Determine if the new path is better than the currently recorded best path to (nr, nc)
                const currentDist = dist[nr][nc];
                const currentColorAtTarget = finalColor[nr][nc];

                let shouldUpdate = false;

                if (newTime < currentDist) {
                    // Case 1: Strictly faster arrival time
                    shouldUpdate = true;
                } else if (newTime === currentDist) {
                    // Case 2: Same arrival time, check color
                    if (currentColor > currentColorAtTarget) {
                        shouldUpdate = true;
                    }
                }

                if (shouldUpdate) {
                    dist[nr][nc] = newTime;
                    finalColor[nr][nc] = currentColor;
                    // Enqueue the neighbor with the new best path information
                    pqInstance.enqueue([newTime, -currentColor, nr, nc]);
                }
            }
        }
    }

    // The finalColor array contains the result
    return finalColor;
}

