   * @param n Number of rows.
   * @param m Number of columns.
   * @param sources Initial colored cells.
   * @return The final grid state with colors.
   */
  def solve(n: Long, m: Long, sources: Array[Array[Long]]): Array[Array[Long]] = {
    val N = n.toInt
    val M = m.toInt

    // dist[r][c] stores the minimum time step for any color to reach (r, c). Initialize to Infinity.
    val dist = Array.fill(0)(Array.fill(0)(Long.MaxValue))

    // finalColor[r][c] stores the final color of cell (r, c). Initialize to 0 (uncolored).
    val finalColor = Array.fill(0)(Array.fill(0)(0L))

    // Priority Queue Element: (Time, NegativeColor, R, C)
    // We use a custom heap or a structure that mimics a min-heap on (Time, NegativeColor).
    // Smallest Time -> Highest Color (smallest NegativeColor)

    // Using a mutable structure to represent the heap for simplicity in this context.
    // Element: (Time: Long, NegColor: Long, R: Int, C: Int)
    val pq = mutable.PriorityQueue[(Long, Long, Int, Int)]()

    // Initialize PQ with all sources
    for (src <- sources) {
      val r = src(0).toInt
      val c = src(1).toInt
      val color = src(2)

      dist(r)(c) = 0L
      finalColor(r)(c) = color

      // Push (Time=0, NegColor=-color, R, C)
      pq.enqueue((0L, -color, r, c))
    }

    val directions = Array((0, 1), (0, -1), (1, 0), (-1, 0))

    while (!pq.isEmpty()) {
      val (time, negColor, r, c) = pq.dequeue()
      val currentColor = -negColor

      // Check for stale entries: If the path pulled is worse than what we already recorded for this cell, skip.
      // A path is worse if time is greater, OR time is equal but the color is smaller.
      if (time > dist(r)(c) || (time == dist(r)(c) && currentColor < finalColor(r)(c))) {
        continue
      }

      // Spread to neighbors
      for ((dr, dc) <- directions) {
        val nr = r + dr
        val nc = c + dc

        if (nr >= 0 && nr < N && nc >= 0 && nc < M) {
          val newTime = time + 1

          val currentDist = dist(nr)(nc)
          val currentColorAtTarget = finalColor(nr)(nc)

          var shouldUpdate = false

          if (newTime < currentDist) {
            // Case 1: Strictly faster arrival time
            shouldUpdate = true
          } else if (newTime == currentDist) {
            // Case 2: Same arrival time, check color (Max color wins)
            if (currentColor > currentColorAtTarget) {
              shouldUpdate = true
            }
          }

          if (shouldUpdate) {
            dist(nr)(nc) = newTime
            finalColor(nr)(nc) = currentColor

            // Enqueue the neighbor with the new best path information
            pq.enqueue((newTime, -currentColor, nr, nc))
          }
        }
      }
    }

    finalColor
  }
}

