  def solve(n: Long, m: Long, sources: Array[Array[Long]]): Array[Array[Long]] = {
    val N = n.toInt
    val M = m.toInt

    // dist[r][c] stores the minimum time step for any color to reach (r, c). Initialize to Infinity.
    val dist = Array.ofDim[Int](N, M).map(_ => Int.MaxValue)
    // finalColor[r][c] stores the final color of cell (r, c). Initialize to 0 (uncolored).
    val finalColor = Array.ofDim[Long](N, M).map(_ => 0L)

