function solve(n, m, sources) {
    // This problem can be solved using a multi-source Breadth-First Search (BFS)
    // where the "distance" is the time it takes for the color to reach a cell,
    // and we prioritize higher colors in case of a tie in time.

    // Initialize the grid: 0 means uncolored, -1 means unvisited/uninitialized for distance tracking
    // We will store the time it took to reach this cell and the color that reached it.
    // Let's use a distance array/grid for BFS and a separate color grid.

    // dist[r][c] stores the minimum time step for any color to reach (r, c).
    const dist = Array(n).fill(0).map(() => Array(m).fill(Infinity));
    // finalColor[r][c] stores the final color of cell (r, c).
    const finalColor = Array(n).fill(0).map(() => Array(m).fill(0));

